  1→//! Staged pipeline: composable Observe → Analyze → Solve → Specify stages.
  2→//!
  3→//! Each stage is a pure function with well-defined input/output types.
  4→//! The Analyze stage groups raw exploration results into equivalence classes,
  5→//! builds a behavior map, and computes coverage metrics.
  6→
  7→use crate::behavior::BehaviorMap;
  8→use crate::coverage_metrics::CoverageMetrics;
  9→use crate::equivalence::{self, EquivalenceClass};
 10→use crate::execution_record::{ExecutionRecord, SymConstraint};
 11→use crate::explorer::ObservationOutput;
 12→use crate::protocol::{ExecuteResult, FunctionAnalysis};
 13→
 14→use std::collections::HashMap;
 15→use std::hash::{DefaultHasher, Hash, Hasher};
 16→
 17→/// Output of the Analyze stage.
 18→#[derive(Debug)]
 19→pub struct AnalyzeOutput {
 20→    /// Equivalence classes grouping executions by branch path.
 21→    pub eq_classes: Vec<EquivalenceClass>,
 22→    /// Behavior map built from execution records.
 23→    pub behavior_map: BehaviorMap,
 24→    /// Branch coverage metrics with per-method attribution.
 25→    pub coverage_metrics: CoverageMetrics,
 26→}
 27→
 28→/// Run the Analyze stage on an observation result.
 29→///
 30→/// Takes the raw exploration output and the static function analysis,
 31→/// then produces equivalence classes, a behavior map, and coverage metrics.
 32→pub fn analyze(observe: &ObservationOutput, analysis: &FunctionAnalysis) -> AnalyzeOutput {
 33→    // Build equivalence classes from raw results.
 34→    let eq_classes = equivalence::group_into_classes(&observe.raw_results);
 35→
 36→    // Build execution records for BehaviorMap construction.
 37→    let records: Vec<ExecutionRecord> = observe
 38→        .raw_results
 39→        .iter()
 40→        .map(|(inputs, _mocks, result)| execution_record_from_result(&observe.function_name, inputs, result))
 41→        .collect();
 42→
 43→    let mut behavior_map = BehaviorMap::from_records(&observe.function_name, &records);
 44→    behavior_map.nondeterministic_fields = observe.nondeterministic_fields.clone();
 45→
 46→    // Deduplicate constraints by branch_id so each branch contributes exactly one classification.
 47→    let unique_constraints: HashMap<u32, SymConstraint> = observe
 48→        .raw_results
 49→        .iter()
 50→        .flat_map(|(_, _mocks, result)| {
 51→            result
 52→                .branch_path
 53→                .iter()
 54→                .map(|d| (d.branch_id, d.constraint.clone()))
 55→        })
 56→        .collect();
 57→    let all_constraints: Vec<SymConstraint> = unique_constraints.into_values().collect();
 58→
 59→    let coverage_metrics = CoverageMetrics::from_exploration(
 60→        analysis.branches.len(),
 61→        &observe.discoveries,
 62→        &all_constraints,
 63→    );
 64→
 65→    AnalyzeOutput {
 66→        eq_classes,
 67→        behavior_map,
 68→        coverage_metrics,
 69→    }
 70→}
 71→
 72→/// Build an [`ExecutionRecord`] from an [`ExecuteResult`] and its inputs.
 73→fn execution_record_from_result(
 74→    function_id: &str,
 75→    inputs: &[serde_json::Value],
 76→    result: &ExecuteResult,
 77→) -> ExecutionRecord {
 78→    let mut hasher = DefaultHasher::new();
 79→    let input_str = serde_json::to_string(inputs).unwrap_or_default();
 80→    input_str.hash(&mut hasher);
 81→    let input_hash = hasher.finish();
 82→
 83→    ExecutionRecord {
 84→        function_id: function_id.to_string(),
 85→        input_hash,
 86→        parameters: inputs.to_vec(),
 87→        branch_path: result.branch_path.clone(),
 88→        scope_events: result.scope_events.clone(),
 89→        lines_executed: result.lines_executed.clone(),
 90→        calls_to_external: result.calls_to_external.clone(),
 91→        path_constraints: result.path_constraints.clone(),
 92→        return_value: result.return_value.clone(),
 93→        thrown_error: result.thrown_error.clone(),
 94→        side_effects: result.side_effects.clone(),
 95→        wall_time_ms: result.performance.wall_time_ms,
 96→        cpu_time_us: result.performance.cpu_time_us,
 97→        heap_used_bytes: result.performance.heap_used_bytes,
 98→        heap_allocated_bytes: result.performance.heap_allocated_bytes,
 99→        timestamp: String::new(),
100→        engine_version: String::new(),
101→    }
102→}
