104→impl From<crate::orchestrator::ExploreResult> for ObservationOutput {
105→    fn from(r: crate::orchestrator::ExploreResult) -> Self {
106→        // Build ExecutionSummary entries from unique-path executions.
107→        let new_path_executions: Vec<crate::explorer::ExecutionSummary> = r
108→            .executions
109→            .iter()
110→            .map(|exec| crate::explorer::ExecutionSummary {
111→                inputs: vec![], // Concolic explorer doesn't pair inputs with executions vec
112→                return_value: exec.return_value.clone(),
113→                thrown_error: exec
114→                    .thrown_error
115→                    .as_ref()
116→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
117→                lines_executed: exec.lines_executed.clone(),
118→                is_new_path: true,
119→                error_intent: crate::explorer::classify_error_intent(exec),
120→            })
121→            .collect();
122→
123→        // Compute lines covered from raw_results.
124→        let mut all_lines: std::collections::HashSet<u32> = std::collections::HashSet::new();
125→        for (_, _mocks, result) in &r.raw_results {
126→            for &line in &result.lines_executed {
127→                all_lines.insert(line);
128→            }
129→        }
130→
131→        Self {
132→            function_name: r.function_name,
133→            iterations: r.total_executions as u32,
134→            unique_paths: r.unique_paths,
135→            lines_covered: all_lines.len(),
136→            total_lines: r.total_lines,
137→            new_path_executions,
138→            raw_results: r.raw_results,
139→            discoveries: r.discoveries,
140→            nondeterministic_fields: r.nondeterministic_fields,
141→            float_probe_results: r.float_probe_results,
142→        }
143→    }
144→}
