/// Regression str-92xe: concolic conversion must preserve inputs in new_path_executions.
/// The From<ExploreResult> impl was setting inputs: vec![] instead of extracting
/// them from raw_results, causing report rendering to show empty call examples.
#[test]
fn concolic_conversion_preserves_inputs() {
    let exec_result = ExecuteResult {
        return_value: Some(json!("positive")),
        thrown_error: None,
        branch_path: vec![BranchDecision {
            branch_id: 0,
            line: 10,
            taken: true,
            constraint: SymConstraint::Unknown { hint: "test".into() },
        }],
        lines_executed: vec![1, 2, 3],
        calls_to_external: vec![],
        path_constraints: vec![],
        side_effects: vec![],
        scope_events: vec![],
        capture_truncation: None,
        performance: empty_perf(),
    };

    let concolic = crate::orchestrator::ExploreResult {
        function_name: "classify".into(),
        total_lines: 10,
        executions: vec![exec_result.clone()],
        unique_paths: 1,
        total_executions: 3,
        z3_generated: 1,
        fuzz_generated: 0,
        boundary_generated: 0,
        drill_generated: 0,
        termination_reason: crate::orchestrator::TerminationReason::WorklistExhausted,
        raw_results: vec![
            (vec![json!(5)], vec![], exec_result.clone()),
            (vec![json!(-1)], vec![], exec_result.clone()),
            (vec![json!(0)], vec![], exec_result),
        ],
        discoveries: vec![(0, DiscoveryMethod::Random)],
        triage_skipped: 0,
        triage_mispredictions: 0,
        nondeterministic_fields: vec![],
        float_probe_results: vec![],
    };

    let output: ObservationOutput = concolic.into();

    // new_path_executions must have non-empty inputs
    assert!(
        !output.new_path_executions.is_empty(),
        "should have new_path_executions from raw_results"
    );
    for exec in &output.new_path_executions {
        assert!(
            !exec.inputs.is_empty(),
            "each new_path_execution must have non-empty inputs, got empty"
        );
    }
}

